const functions = require("firebase-functions");
const JSZip = require("jszip");

const DAILY_REF_B64  = "";
const WEEKLY_REF_B64 = "";

// 원본 텍스트 교체 위치 (하드코딩)
const POS = {
  sumS_pE:  11288, sumE_pS:  15159, sumE_pE:  15491,
  manE_pS:  16125, origS_pE: 38109, origE_pS: 41987,
  prop_pS:  43102, prop_pE:  43445,
  biz_pE:   50311, sec_end:  62584,
};

// 주요일정 셀 위치 (새 원본 기준)
const SCHED_CELLS = [
  [[19894,20033],[20502,20641],[21111,21250]],
  [[21735,21874],[22343,22482],[22952,23091]],
  [[23576,23715],[24184,24323],[24793,24932]],
  [[25417,25556],[26025,26164],[26634,26773]],
  [[27258,27397],[27866,28005],[28475,28614]],
  [[29099,29238],[29707,29846],[30316,30455]],
];

let pid = 9000000000;
function newPid(){ return String(++pid); }
function ex(s){ return String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;"); }
function mp(p, runs){
  const r = runs.map(([c,t])=>`<hp:run charPrIDRef="${c}"><hp:t>${ex(t)}</hp:t></hp:run>`).join("");
  return `<hp:p id="${newPid()}" paraPrIDRef="${p}" styleIDRef="0" pageBreak="0" columnBreak="0" merged="0">${r}</hp:p>`;
}
function ip(list){
  if(!list||!list.length) return mp("14",[["9","  ○ "],["66","(해당 없음)"]]);
  return list.map(iss=>
    mp("14",[["9","  ○ "],["66",iss.project||""]]) +
    (iss.items||[]).map(it=>mp("89",[["75","    - "],["71",it]])).join("")
  ).join("");
}

function replaceFirstCellText(xml, tblIdx, runs, prIDRef){
  const tbls=[...xml.matchAll(/<hp:tbl[ >]/g)];
  if(!tbls[tblIdx]) return xml;
  const sub=xml.indexOf("<hp:subList>", tbls[tblIdx].index);
  if(sub<0) return xml;
  const pS=xml.indexOf("<hp:p ",sub), pE=xml.indexOf("</hp:p>",pS)+7;
  const r=runs.map(([c,t])=>`<hp:run charPrIDRef="${c}"><hp:t>${ex(t)}</hp:t></hp:run>`).join("");
  return xml.slice(0,pS)+`<hp:p id="${newPid()}" paraPrIDRef="${prIDRef||"21"}" styleIDRef="0" pageBreak="0" columnBreak="0" merged="0">${r}</hp:p>`+xml.slice(pE);
}

function replaceTableRow(xml, tblIdx, rowIdx, cells){
  const tbls=[...xml.matchAll(/<hp:tbl[ >]/g)];
  if(!tbls[tblIdx]) return xml;
  const tS=tbls[tblIdx].index;
  const rows=[...xml.slice(tS).matchAll(/<hp:tr[ >]/g)];
  if(!rows[rowIdx]) return xml;
  const rS=tS+rows[rowIdx].index;
  const subs=[...xml.slice(rS).matchAll(/<hp:subList>/g)];
  let res=xml, off=0;
  cells.forEach((runs,ci)=>{
    if(!subs[ci]) return;
    const cPos=rS+subs[ci].index;
    const pS=res.indexOf("<hp:p ",cPos+off), pE=res.indexOf("</hp:p>",pS)+7;
    const r=runs.map(([c,t])=>`<hp:run charPrIDRef="${c}"><hp:t>${ex(t)}</hp:t></hp:run>`).join("");
    const np=`<hp:p id="${newPid()}" paraPrIDRef="21" styleIDRef="0" pageBreak="0" columnBreak="0" merged="0">${r}</hp:p>`;
    const prev=res.length; res=res.slice(0,pS)+np+res.slice(pE); off+=res.length-prev;
  });
  return res;
}

function replaceParaByMarker(xml, marker, newPara){
  const idx=xml.indexOf(marker);
  if(idx<0) return xml;
  const pS=xml.lastIndexOf("<hp:p ",idx), pE=xml.indexOf("</hp:p>",pS)+7;
  return xml.slice(0,pS)+newPara+xml.slice(pE);
}

async function buildDailyHWPX(data){
  pid = 9000000000;
  const zip = await JSZip.loadAsync(Buffer.from(DAILY_REF_B64,"base64"));
  let xml = await zip.file("Contents/section0.xml").async("string");

  // 1. 제목
  xml = replaceFirstCellText(xml,0,
    [["2","크리에이티브그룹 일일상황보고 요약보고 "],["4",`(${data.date||""})`]],"21");

  // 2. 본부 주요행사
  const ev=(data.main_events||[])[0]||{div:"",content:"",note:""};
  xml = replaceTableRow(xml,1,1,[[["9",ev.div||""]],[["9",ev.content||""]],[["9",ev.note||""]]]);

  // 5. 주요일정 (하드코딩 셀 위치로 직접 교체)
  const sc = data.schedule||[];
  const reps = [];
  for(let i=0;i<6;i++){
    const s = sc[i]||{date:"",detail:"",note:""};
    const vals = [s.date||"", s.detail||"", s.note||""];
    SCHED_CELLS[i].forEach(([ps,pe],ci)=>{
      const txt = ex(vals[ci]);
      const np = `<hp:p id="0" paraPrIDRef="21" styleIDRef="0" pageBreak="0" columnBreak="0" merged="0"><hp:run charPrIDRef="9"><hp:t>${txt}</hp:t></hp:run></hp:p>`;
      reps.push([ps,pe,np]);
    });
  }
  reps.sort((a,b)=>b[0]-a[0]);
  for(const [f,t,c] of reps) xml=xml.slice(0,f)+c+xml.slice(t);

  // 8. 제안목록
  if((data.proposals||[]).length>0){
    xml = replaceTableRow(xml,4,1,[
      [["46",data.proposals[0].title||""]],[["47",data.proposals[0].person||""]],[["47",data.proposals[0].date||""]]
    ]);
  }

  // 텍스트 교체 (뒤→앞 순서로 한번에)
  const segs = [];

  // 공공사업 교체
  const bizContent = (data.biz_details||[]).length>0
    ? (data.biz_details||[]).map(b=>
        mp("75",[["18",`    - ${b.name||""}`]])+
        (b.details||[]).map(d=>mp("88",[["18",`      ㆍ${d}`]])).join("")
      ).join("")
    : mp("75",[["18","    - (해당 없음)"]]);
  segs.push([POS.biz_pE, POS.sec_end, bizContent]);

  // 제안요약
  segs.push([POS.prop_pS, POS.prop_pE,
    mp("75",[["18",`    - ${data.proposal_summary||"해당 없음"}`]])]);

  // 원본 현안이슈
  segs.push([POS.origS_pE, POS.origE_pS, ip(data.orig_issues)]);

  // 인력동향
  const man = (data.manpower&&data.manpower.length?data.manpower:["특이사항 없음"])
    .map(m=>mp("12",[["9",`  ○ ${m}`]])).join("");
  segs.push([POS.sumE_pE, POS.manE_pS, man]);

  // 요약 현안이슈
  segs.push([POS.sumS_pE, POS.sumE_pS, ip(data.sum_issues)]);

  segs.sort((a,b)=>b[0]-a[0]);
  for(const [f,t,c] of segs) xml=xml.slice(0,f)+c+xml.slice(t);

  zip.file("Contents/section0.xml", xml);
  return await zip.generateAsync({type:"nodebuffer",compression:"DEFLATE"});
}

exports.generateHWPX = functions
  .region("asia-northeast1")
  .runWith({memory:"512MB",timeoutSeconds:60})
  .https.onRequest(async(req,res)=>{
    res.set("Access-Control-Allow-Origin","*");
    res.set("Access-Control-Allow-Methods","POST,OPTIONS");
    res.set("Access-Control-Allow-Headers","Content-Type");
    if(req.method==="OPTIONS"){res.status(204).send("");return;}
    if(req.method!=="POST"){res.status(405).send("Method Not Allowed");return;}
    try{
      const {type,data}=req.body;
      const buf=await buildDailyHWPX(data||{});
      const fn=encodeURIComponent("일일상황보고_크리에이티브그룹.hwpx");
      res.set("Content-Type","application/octet-stream");
      res.set("Content-Disposition",`attachment; filename*=UTF-8''${fn}`);
      res.send(buf);
    }catch(e){
      console.error("오류:",e);
      res.status(500).json({error:e.message});
    }
  });
// v-clean
// deploy-v3
